import { FiCheckSquare } from 'react-icons/fi';
const TasksPage = () => (
  <div className="flex flex-col gap-6">
    <h1 className="text-2xl font-bold text-gray-900">Tâches — Kanban</h1>
    <div className="grid grid-cols-3 gap-4">
      {['À faire', 'En cours', 'Terminé'].map((col) => (
        <div key={col} className="card p-4">
          <h2 className="text-sm font-semibold text-gray-600 mb-4 flex items-center gap-2">
            <FiCheckSquare size={15} /> {col}
          </h2>
          <div className="flex flex-col gap-2">
            <div className="rounded-lg border border-gray-100 p-3 bg-gray-50 text-sm text-gray-400 text-center">
              Connectez au task-service (port 3003)
            </div>
          </div>
        </div>
      ))}
    </div>
  </div>
);
export default TasksPage;
